export function nextGeneration(liveCells: Cell[]): Cell[] {
  const isLive = (x: number, y: number): boolean =>
    liveCells.some(([lx, ly]) => lx === x && ly === y);

  const countLiveNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isLive(x + dx, y + dy)).length;

  const survivors = liveCells.filter(([x, y]) => {
    const liveNeighbors = countLiveNeighbors(x, y);
    return liveNeighbors === 2 || liveNeighbors === 3;
  });

  const candidates: Cell[] = [];
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      if (!isLive(nx, ny) && !candidates.some(([cx, cy]) => cx === nx && cy === ny)) {
        candidates.push([nx, ny]);
      }
    }
  }
  const births = candidates.filter(([x, y]) => countLiveNeighbors(x, y) === 3);

  return [...survivors, ...births];
}

