export function nextGeneration(liveCells: Cell[]): Cell[] {
  const includesCell = (cells: Cell[], x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);

  const isLive = (x: number, y: number): boolean => includesCell(liveCells, x, y);

  const neighborsOf = ([x, y]: Cell): Cell[] =>
    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy] as Cell);

  const countLiveNeighbors = (cell: Cell): number =>
    neighborsOf(cell).filter(([x, y]) => isLive(x, y)).length;

  const survivors = liveCells.filter((cell) => {
    const liveNeighbors = countLiveNeighbors(cell);
    return liveNeighbors === 2 || liveNeighbors === 3;
  });

  const deadNeighbors = liveCells
    .flatMap(neighborsOf)
    .filter(([x, y]) => !isLive(x, y))
    .filter(([x, y], i, arr) => !includesCell(arr.slice(0, i), x, y));

  const births = deadNeighbors.filter((cell) => countLiveNeighbors(cell) === 3);

  return [...survivors, ...births];
}
